const raw = $input.first().json || {};
const body = raw.body || raw;
if (String(body.action || '').toLowerCase() !== 'triggered') {
  return [];
}

const data = body.data || {};
const issue = data.issue || {};
const event = data.event || {};
const level = String(issue.level || event.level || 'error').toLowerCase();
if (level === 'info' || level === 'warning') {
  return [];
}

const projectSlug = String(body.project_slug || issue.project?.slug || '').trim();
const routing = {
  'cfipros-backend': 'cfipros',
  'cfipros-frontend': 'cfipros'
};
const projectKey = routing[projectSlug];
if (!projectKey) {
  return [];
}

const issueId = String(issue.id || '').trim();
const eventId = String(event.event_id || '').trim();
const titleSource = String(issue.title || event.title || 'Sentry issue').trim();
const dedupSeed = issueId || eventId || 'unknown';
const tags = event.tags || [];
const repoTag = tags.find(tag => (Array.isArray(tag) ? tag[0] : tag.key) === 'repo');
const repoName = repoTag ? (Array.isArray(repoTag) ? repoTag[1] : repoTag.value) : 'marcusgoll/cfipros';

return [{ json: {
  router_mode: 'intake',
  schema_version: 1,
  source: 'n8n',
  type: 'sentry_issue',
  project_key: projectKey,
  title: 'Investigate ' + projectKey + ' Sentry issue: ' + titleSource,
  action_key: '',
  dedup_key: 'sentry_issue:' + projectKey + ':' + dedupSeed,
  requested_by: 'sentry',
  payload: {
    issue_id: issueId,
    event_id: eventId,
    project_slug: projectSlug,
    level,
    title: titleSource,
    culprit: String(issue.culprit || event.culprit || ''),
    web_url: String(issue.web_url || ''),
    repo: String(repoName || ''),
    sentry_payload: body
  }
} }];
